const int MAXN = 1e6;
int s[2 * N], p[2 * N][30], val[2 * N], depth[2 * N];
int a[N], vis[N];
vector<int> f[N], g[2 * N];
void solve(int CASE)
{
	int n, q; cin >> n >> q;
	int m = 0;
	fa(i, 1, n) {
		cin >> a[i];
		if (!vis[a[i]]) {
			m++;
			vis[a[i]] = m;
		}
	}
	fa(i, 1, MAXN)for (int j = i; j <= MAXN; j += i) {
		if (vis[j])f[i].pb(vis[j]);
	}

	fa(i, 1, 2 * m)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};

	// 建图
	int now_cnt = m;
	fb(w, MAXN, 1)if (f[w].size() >= 2) {
		fa(i, 1, vs(f[w])) {
			int e1 = find(find, f[w][i - 1]);
			int e2 = find(find, f[w][i]);
			if (e1 != e2) {
				now_cnt++;
				val[now_cnt] = w;
				g[now_cnt].pb(e1), g[now_cnt].pb(e2);
				s[e1] = s[e2] = now_cnt;
				p[e1][0] = p[e2][0] = now_cnt;
			}
		}
	}

	var dfs = [&](var dfs, int now, int fa)->void {
		depth[now] = depth[fa] + 1;
		for (int i = 1; (1 << i) <= depth[now]; i++) {
			p[now][i] = p[p[now][i - 1]][i - 1];
		}
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
		}
		};
	dfs(dfs, now_cnt, 0);

	var lca = [&](int x, int y)->int {
		if (depth[x] < depth[y])swap(x, y);
		fb(i, 29, 0)if (depth[x] - (1 << i) >= depth[y])
			x = p[x][i];
		if (x == y)return x;
		fb(i, 29, 0)if (p[x][i] != p[y][i])
			x = p[x][i], y = p[y][i];
		return p[x][0];
		};

	while (q--) {
		int x, y; cin >> x >> y;
		if (a[x] == a[y])cout << a[x] << endl;
		else cout << val[lca(vis[a[x]], vis[a[y]])] << endl;
	}
	return;
}
